var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"쳇, 꽤 하잖아?","JPN":"ちっ、やるじゃない。","ENG":"Tch. You're pretty good, I'll give you that.","TWN":"嘖，還挺厲害的嘛？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이래서 성황청의 미친개들이랑 엮이고 싶지 않았는데……!","JPN":"これだから聖皇庁の狂犬どもとは関わりたくなかったのに……！","ENG":"This's exactly why I never wanted to get involved with the Holy Curia's mad dogs...","TWN":"所以我才不想跟聖皇廳的瘋狗扯上關係……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"닥치세요, 이단자!","JPN":"黙りなさい、異端者！","ENG":"Shut up, heretic!","TWN":"閉嘴吧，異端者！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"마지막 경고입니다. 그 변절자를 처단하지 못하면, 많은 사람들이 다칠 거예요!","JPN":"最後の警告です。あの変節者を処断しなければ、大勢の人に危害が及びます！","ENG":"This is your final warning. If we fail to execute that betrayer, many people will be hurt.","TWN":"這是最後警告。如果無法阻止那個叛徒，會有很多人受傷！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이단이라고 해도, 주님을 모시는 사제가 그걸 두고 볼 셈인가요?","JPN":"異端とはいえ主に仕える司祭が、それを傍観するつもりですか？","ENG":"Even if they are heretics, are you saying a priest who serves the Lord will simply stand by and watch?","TWN":"就算是異端，侍奉主的司祭也打算坐視不管嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"글쎄, 시장을 보니, 우리 주님께서는 별 반응이 없으시네.","JPN":"さあ、市場を見た感じ、金が転がり込む予兆はないみたいね。","ENG":"Well, judging by the market, our Lord does not seem to be reacting much.","TWN":"嗯，看看市場走勢，我們的主似乎沒什麼反應呢。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"예전부터 샤레이드 테마주는 조금 떨어질 필요가 있다고 생각했거든.","JPN":"前からシャレードの価値はちょっと過大評価されてると思ってたんだけど。","ENG":"I've always thought Charade-related stocks needed to drop a bit anyway.","TWN":"我早就覺得查雷德的概念股該跌一點了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"무슨 소리죠, 테마주?","JPN":"何を言っているんですか？　価値？","ENG":"Stocks? What are you talking about?","TWN":"你在說什麼？概念股？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 내가 얘기 안 했나? 내가 믿는 주님은 주식님이라서~","JPN":"あ、言ってなかった？　私の信じる主はお金だからね～","ENG":"Oh, did I not mention? The only \\"Lord\\" I believe in is money.","TWN":"啊，我沒說過嗎？我信奉的主是股神喔～"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이 세상에서 오병이어의 기적을 행사할 수 있는 건, 오직 주식뿐이라고?","JPN":"この世界で5つのパンと2匹の魚の奇跡を起こせるのは、金だけだよ？","ENG":"The only thing in this world that can perform the miracle of feeding the multitudes is stocks, you know.","TWN":"這世上能施展五餅二魚奇蹟的，只有股票不是嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주식님? 이 무슨 불경한……!","JPN":"金？　なんと不敬な……！","ENG":"Money? What kind of blasphemy is this...?!","TWN":"股神？這是何等褻瀆……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 이 톱날들은……?","JPN":"な、何？　このチェーンソー……？","ENG":"W-what? Saw blades...?","TWN":"什、什麼？這些鋸齒是……？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈 뜯으러 온 빚쟁이 마냥 계속 따라붙잖아?","JPN":"借金取りみたいにつきまとってくる！","ENG":"They keep chasing me like debt collectors coming to squeeze money out of me.","TWN":"跟討債的一樣一直追著不放耶？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"그야 내 체인소는 한 번 발사된 이상, 절대 멈추지 않으니까.","JPN":"アタシのチェーンソーは一度発射したら絶対止まらないから。","ENG":"Once my chainsaw is fired, it never stops.","TWN":"因為我的鏈鋸一旦射出，就絕對不會停下來。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"팔다리 몽땅 갈리고 싶지 않으면 꺼져, 이 반푼이들아.","JPN":"四肢を切り刻まれたくなければさっさと失せろ、雑魚ども。","ENG":"If you don't want all your limbs shredded, get lost, you halfwits.","TWN":"不想手腳全被絞碎就滾開，你們這群半吊子。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"헷, 꼬맹이 주제에 살벌하잖아?","JPN":"はっ、ガキのくせに殺気立っちゃって。","ENG":"Heh, pretty vicious for a kid, no?","TWN":"哼，小鬼還挺兇的嘛？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 우리 꼬맹이도 맛탱이 간 걸로는 어디서 꿀리지 않는다고!","JPN":"でも、うちのガキもイカれ具合なら負けないから！","ENG":"But our kid isn't lacking when it comes to being completely unhinged either.","TWN":"不過我們家的小鬼在瘋狂程度上可不輸任何人！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지금이야, 카타리나……!","JPN":"今だよ、カタリナ……！","ENG":"Now, Katharina...!","TWN":"就是現在，卡特莉娜……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"알고 있다고요, 불량식품!","JPN":"わかってます、お菓子さん！","ENG":"I know, Junk food!","TWN":"我知道啦，垃圾食物！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"침식체? 잘 됐네! 써는 맛이 있겠는데!","JPN":"侵食体？　いいね。切り甲斐がありそうだ！","ENG":"A C.O.? Perfect! That should be fun to carve up!","TWN":"侵蝕體？太好了！切起來一定很爽！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"물러나세요, 시스터 루퍼!","JPN":"下がりなさい、シスター・ルーパー！","ENG":"Fall back, Sister Looper!","TWN":"退下，洛珀姐妹！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"게티아로 불러낸 것들은 물리적인 실체가 없는 영체예요!","JPN":"ゴエティアで呼び出したものは、実体を持たない霊体です！","ENG":"The ones summoned by Goetia are incorporeal spirits without physical bodies!","TWN":"用巫術書召喚出來的是沒有實際實體的靈體！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신 카운터 능력과는 상성이 안 맞습니다!","JPN":"あなたのカウンター能力とは相性が良くありません！","ENG":"They are a terrible match for your Counter abilities!","TWN":"和你的制裁者能力不相容！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_PR","text":{"KOREA":"에잇, 그딴 거 몰라……!","JPN":"ええいっ、そんなもん知るか……！","ENG":"Damn it, I don't care about that...!","TWN":"吵死了，我才不管那種事……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"큿, 하여간 당신은……!","JPN":"くっ、あなたって人は……！","ENG":"Honestly, you really are–!","TWN":"嘖，你這人真是……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"게, 게티아가 갑자기 닫히다니……?","JPN":"ゴ、ゴエティアが急に閉じた……？","ENG":"W-why did Goetia suddenly close...?","TWN":"巫、巫術書竟然突然關閉了……？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청 비밀 서고에는 수많은 <color=#ffd34c>금서</color>가 존재하죠.","JPN":"聖皇庁の秘密書庫には数多くの<color=#ffd34c>禁書</color>が存在します。","ENG":"There are countless <color=#ffd34c>forbidden books</color> in the Holy Curia's secret library.","TWN":"聖皇廳的祕密書庫中，收藏著無數<color=#ffd34c>禁書</color>。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 금서에는 저마다 위험한 능력이 잠들어 있지만…….","JPN":"それぞれの禁書には危険な能力が眠っていますが……","ENG":"Each of them holds a dangerous power...","TWN":"那些禁書各自封印著危險的能力……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>종이</color>로 된 책인 이상, 제 능력에서 벗어날 수 없어요.","JPN":"<color=#ffd34c>紙</color>でできた本である以上、私の能力からは逃れられません。","ENG":"But as long as they are books made of <color=#ffd34c>paper</color>, they cannot escape my ability.","TWN":"但只要是<color=#ffd34c>紙張</color>構成的書，就無法脫離我的能力。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그것이 제가 비밀 서고의 사서였던 이유입니다.","JPN":"他でもない私が、秘密書庫の司書である理由です。","ENG":"That is why I was the librarian of that place.","TWN":"這正是我曾為祕密書庫圖書管理員的理由。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_PR","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"唔……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어쩐지 낯이 익다 싶었는데, 이제야 알겠군요.","JPN":"どおりで見覚えのある顔だと思いましたが、やっとわかりました。","ENG":"I thought you looked familiar. Now I see why.","TWN":"難怪總覺得眼熟，現在我終於明白了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신, 성황청의 견습 수녀로군요.","JPN":"あなた、聖皇庁の見習いシスターですね。","ENG":"You are an apprentice nun of the Holy Curia.","TWN":"你，是聖皇廳的實習修女吧。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};